static const char *g_names[CLF_N_CLASSES] = {
    "ambient",                 /* 0 */
    "Gryllus campestris",      /* 1 */
    "Acheta domesticus",       /* 2 */
    "Oecanthus spp.",          /* 3 */
    "Tibicen spp.",            /* 4 */
    "Magicicada spp.",         /* 5 */
    "Locusta migratoria",      /* 6 */
    "Schistocerca gregaria",   /* 7 */
    "Reticulitermes flavipes", /* 8 */
    "Coptotermes formosanus",  /* 9 */
    "Camponotus spp.",         /* 10 */
    "Hylotrupes bajulus",      /* 11 */
    "Anobium punctatum",       /* 12 */
    "Sitophilus granarius",    /* 13 */
    "Sitophilus oryzae",       /* 14 */
    "Tribolium castaneum",     /* 15 */
    "Plodia interpunctella",   /* 16 */
    "Cydia pomonella",         /* 17 */
    "Lygus spp.",              /* 18 */
    "Empoasca spp.",           /* 19 */
    "Nezara viridula",         /* 20 */
    "Halictus spp.",           /* 21 */
    "Achroia grisella",        /* 22 */
    "Tineola bisselliella",    /* 23 */
    "Lasius spp.",             /* 24 */
    "unknown",                 /* 25 */
};

const char *clf_species_name(int id) {
    if (id < 0 || id >= CLF_N_CLASSES) return "invalid";
    return g_names[id];
}